import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Other Networks & iOS 14 FAQ","description":"","frontmatter":{"title":"Other Networks & iOS 14 FAQ","slug":"other-networks-ios-14-faq"},"headers":[],"relativePath":"marketer-hub/other-networks-ios-14-faq.md","filePath":"marketer-hub/other-networks-ios-14-faq.md"}'),o={name:"marketer-hub/other-networks-ios-14-faq.md"};function n(s,e,d,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<details><summary>What are Twitter’s plans for iOS 14 changes?</summary><p>We&#39;re in close communication with the Twitter team. <a href="https://business.twitter.com/en/blog/twitter-ios14-updates.html" target="_blank" rel="noreferrer">They are supporting Apple&#39;s SKAdNetwork framework</a>. Rather than forwarding Postbacks like many other networks, Twitter is sharing this data with MMPs (including Branch) via an aggregate API. This means we are able to ingest campaign results data, and continue providing aggregate reporting for your Twitter ads.</p><p>This data is available in the Branch dashboard as long as you have enabled and authenticated with Twitter in the Partner Management section of the dashboard and have authenticated your app for SKAdNetwork reporting; no additional action is needed for this data to start flowing.</p></details><details><summary>Will Twitter show the ATT prompt and provide device-level data for users that opt in?</summary><p>Twitter will show the AppTrackingTransparency prompt, and their existing MMP API endpoint will continue to return device-level data <em>in addition</em> to SKAdNetwork if the user opts in on both ends.</p></details><details><summary>What are TikTok’s plans for iOS 14 changes?</summary><p>TikTok will be relying primarily on SKAdNetwork for attribution, and will forward individual SKAN Postbacks to Branch. In addition, they will also show the ATT prompt to enable device-level attribution for opted-in users.</p><p>TikTok has published the following resources related to iOS 14:</p><ul><li><a href="https://ads.tiktok.com/help/article?aid=10000858" target="_blank" rel="noreferrer">iOS 14 Impact &amp; Guidance Overview</a></li><li><a href="https://ads.tiktok.com/help/article?aid=10001074" target="_blank" rel="noreferrer">New iOS 14 Product Experience in TikTok Ads Manager</a></li></ul></details><details><summary>What are Pinterest’s plans for iOS 14 changes?</summary><p>Prior to Apple&#39;s updated policy lanuage in January 2021, Pinterest was not planning to support SKAdNetwork in the short term. They have not yet issued updated guidance.</p></details><details><summary>Can ad networks still target ad campaigns using identifiers such as phone numbers, emails, names, etc.?</summary><p>This depends on the ad network, and whether the data is available to them in a first-party context.</p><p>A walled garden network like Facebook will likely have no problem continuing to use their first-party data about their own end users to target ads. However, other networks that don&#39;t have their own store of first-party data for targeting won&#39;t have that option (for example, re-targeting campaigns where the audience was generated somewhere else and then imported into the network&#39;s system as a list of IDFAs).</p></details>',5)])])}const c=t(o,[["render",n]]);export{u as __pageData,c as default};
